<?php require_once '../config/koneksi.php'; $omset=0;$iklan=0;$order=0; $q1=mysqli_query($conn,'SELECT SUM(total) total_order, COUNT(*) jumlah_order FROM orderan'); if($r=mysqli_fetch_assoc($q1)){ $omset=$r['total_order']??0; $order=$r['jumlah_order']??0; } $q2=mysqli_query($conn,'SELECT SUM(biaya_iklan) total_iklan FROM iklan'); if($r=mysqli_fetch_assoc($q2)){ $iklan=$r['total_iklan']??0; } $roas=$iklan>0?($omset/$iklan):0; ?><!DOCTYPE html><html><head><title>Laporan - Zans Decor</title><link rel='stylesheet' href='../assets/css/style.css'></head><body><div class='sidebar'><h2>Zans Decor</h2><a href='dashboard.php'>Dashboard</a><a href='produk.php'>Produk</a><a href='order.php'>Order</a><a href='iklan.php'>Iklan</a><a href='laporan.php'>Laporan</a></div><div class='content'><h2>Laporan Bisnis</h2><div class='card'><h3>Total Omset</h3><h2>Rp <?php echo number_format($omset,0,",", "."); ?></h2></div><div class='card'><h3>Total Order</h3><h2><?php echo $order; ?></h2></div><div class='card'><h3>Total Biaya Iklan</h3><h2>Rp <?php echo number_format($iklan,0,",", "."); ?></h2></div><div class='card'><h3>ROAS</h3><h2><?php echo number_format($roas,2); ?> x</h2></div></div></body></html>